import{_ as s,c as a,o as i,d}from"./plugin-vue_export-helper.d4b2cde8.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 12","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 12","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-08-20T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/12.md","lastUpdated":1625430210000}',p={},c=d('<div class="stanza"><a href="#s12.1" id="s12.1" class="num">12.1</a><p>\u0417\u0430\u0442\u0435\u043C \u0441 \u0432\u043E\u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u0432\u044B\u0441\u043B\u0443\u0448\u0430\u0432 \u044D\u0442\u0443 \u0440\u0435\u0447\u044C \u0411\u043E\u0433\u0430 \u0431\u043E\u0433\u043E\u0432, \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u044F\u0441\u043D\u0443\u044E, \u0442\u0432\u043E\u0440\u044F\u0449\u0430\u044F \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u043C\u0438\u0440\u0443;</p></div><div class="stanza"><a href="#s12.2" id="s12.2" class="num">12.2</a><p>\u0414\u043E\u0432\u043E\u043B\u044C\u043D\u0430\u044F, \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u0430\u044F, \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u0435\u043C \u0414\u0435\u0432\u0438, \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u0430\u044F \u0441\u043E\u043D\u043C\u043E\u043C \u0431\u043E\u0433\u043E\u0432, \u043F\u043E\u043A\u043B\u043E\u043D\u0438\u0432\u0448\u0438\u0441\u044C \u0423\u043D\u0438\u0447\u0442\u043E\u0436\u0438\u0442\u0435\u043B\u044E \u0441\u043B\u0435\u043F\u043E\u0442\u044B, \u0432\u043D\u043E\u0432\u044C \u0441\u043A\u0430\u0437\u0430\u043B\u0430 \u0411\u0445\u0430\u0440\u0430\u0442\u0438:</p></div><div class="stanza"><a href="#s12.3" id="s12.3" class="num">12.3</a><p>\u041F\u0440\u0435\u0436\u0434\u0435 \u0422\u043E\u0431\u043E\u0439 \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E, \u0447\u0442\u043E \u0439\u043E\u0433\u0438\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u0439\u043E\u0433\u0443. \u041A\u0430\u043A \u0436\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F \u044D\u0442\u0430 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0430? \u041F\u043E\u0432\u0435\u0434\u0430\u0439 \u043E \u0413\u0443\u0431\u0438\u0442\u0435\u043B\u044C \u0422\u0440\u0438\u043F\u0443\u0440\u044B!</p></div><div class="stanza"><a href="#s12.4" id="s12.4" class="num">12.4</a><p>\u041D\u0430 \u0441\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0435 \u0442\u0430\u043A \u0412\u043B\u0430\u0434\u044B\u0447\u0438\u0446\u0435\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u0411\u0445\u0430\u0440\u0430\u0432\u0430, \u0443\u0441\u0442\u0440\u0430\u043D\u0438\u0442\u0435\u043B\u044C \u0441\u0442\u0440\u0430\u0445\u0430, \u0441\u043A\u0430\u0437\u0430\u043B \u0433\u043B\u0443\u0431\u043E\u043A\u043E \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u044B\u0439 \u0442\u0430\u043A\u0443\u044E \u043C\u0443\u0434\u0440\u0443\u044E \u0440\u0435\u0447\u044C:</p></div><div class="stanza"><a href="#s12.5" id="s12.5" class="num">12.5</a><p>\u0423\u0441\u043B\u044B\u0448\u044C (\u0438\u0441\u0442\u0438\u043D\u0443) \u043E \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435 \u0439\u043E\u0433\u0438, \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u043D\u0443\u044E \u043C\u043D\u043E\u044E \u0440\u0430\u043D\u0435\u0435. \u0423\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u043D\u0435\u0439, \u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435 \u0439\u043E\u0433\u0438\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0441\u0438\u0434\u0434\u0445\u0438 .</p></div><div class="stanza"><a href="#s12.6" id="s12.6" class="num">12.6</a><p>\u0412 \u043F\u0435\u0449\u0435\u0440\u0435 \u0438\u043B\u0438 \u0437\u0435\u043C\u043B\u044F\u043D\u043A\u0435, \u0432 \u0431\u0435\u0437\u0437\u0432\u0443\u0447\u043D\u043E\u043C \u0440\u0430\u0434\u0443\u044E\u0449\u0435\u043C \u0443\u043C (\u043C\u0435\u0441\u0442\u0435), \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u043C \u0432\u0441\u0435\u0445 \u043F\u043E\u043C\u0435\u0445, \u0439\u043E\u0433\u0438\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u0439\u043E\u0433\u0443 .</p></div><div class="stanza"><a href="#s12.7" id="s12.7" class="num">12.7</a><p>\u041F\u043E\u0431\u0435\u0434\u0438\u0432\u0448\u0438\u0439 \u0430\u0441\u0430\u043D\u0443, \u043F\u043E\u0431\u0435\u0434\u0438\u0432\u0448\u0438\u0439 \u0443\u043C, \u043F\u043E\u0431\u0435\u0434\u0438\u0432\u0448\u0438\u0439 \u043F\u0440\u0430\u043D\u0443, \u043F\u043E\u0431\u0435\u0434\u0438\u0432\u0448\u0438\u0439 \u0447\u0443\u0432\u0441\u0442\u0432\u0430, \u043F\u043E\u0431\u0435\u0434\u0438\u0432\u0448\u0438\u0439 \u0441\u043E\u043D, \u043F\u043E\u0431\u0435\u0434\u0438\u0432\u0448\u0438\u0439 \u0433\u043D\u0435\u0432, \u043F\u043E\u0431\u0435\u0434\u0438\u0432\u0448\u0438\u0439 \u043F\u043E\u0440\u044B\u0432\u044B \u0438 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 (\u0432 \u044D\u0442\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438)</p></div><div class="stanza"><a href="#s12.8" id="s12.8" class="num">12.8</a><p>\u0412\u043B\u0430\u0434\u044B\u043A\u0430 \u0439\u043E\u0433\u0438 \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432, \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F \u0443\u043C\u0430, (\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F \u0442\u0430\u0442\u0442\u0432) \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0437\u0435\u043C\u043B\u0438 \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0428\u0430\u043A\u0442\u0438 .</p></div><div class="stanza"><a href="#s12.9" id="s12.9" class="num">12.9</a><p>\u0420\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430, \u0441\u0438\u043C\u0432\u043E\u043B\u0430 (\u0432\u0438\u0433\u0440\u0430\u0445\u0430), \u0431\u0438\u043D\u0434\u0443, \u0432\u0430\u0440\u043D\u044B, \u0431\u0445\u0443\u0432\u0430\u043D\u044B \u0438 \u0430\u0434\u0445\u0432\u044B- \u0442\u0430\u043A\u043E\u0432\u044B \u0448\u0435\u0441\u0442\u044C \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0439, \u043A\u0430\u043A \u043E \u043D\u0438\u0445 \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442\u0441\u044F .</p></div><div class="stanza"><a href="#s12.10" id="s12.10" class="num">12.10</a><p>\u0420\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E, \u0438 \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u044E\u0449\u0435\u0435 (\u0438\u0445)- \u0442\u0430\u043A \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0442\u0440\u0438 \u0432\u0438\u0434\u0430 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430 (\u0432\u0439\u043E\u043C\u0430). \u0411\u0438\u043D\u0434\u0443 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0434\u0435\u0441\u044F\u0442\u0435\u0440\u0438\u0447\u043D\u044B\u043C .</p></div><div class="stanza"><a href="#s12.11" id="s12.11" class="num">12.11</a><p>\u041A\u0430\u0434\u0430\u043C\u0431\u0430\u0433\u043E\u043B\u0430\u043A\u0430\u0440\u0430, \u0441\u0438\u044F\u044E\u0449\u0430\u044F \u0441\u0432\u0435\u0442\u043E\u043C \u043C\u0435\u0440\u0446\u0430\u044E\u0449\u0435\u0439 \u0437\u0432\u0435\u0437\u0434\u044B, \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u043C\u0430\u044F \u043D\u0430 \u0431\u0435\u043B\u044B\u0439 \u043F\u0440\u043E\u0447\u0438\u0435 (\u0446\u0432\u0435\u0442\u0430)- \u0442\u0430\u043A\u043E\u0432\u0430 \u0435\u0434\u0438\u043D\u0430\u044F \u0434\u0435\u0441\u044F\u0442\u0435\u0440\u0438\u0447\u043D\u0430\u044F \u0431\u0438\u043D\u0434\u0443 .</p></div><div class="stanza"><a href="#s12.12" id="s12.12" class="num">12.12</a><p>\u041A\u043E\u043B\u043E\u043A\u043E\u043B\u044C\u0447\u0438\u043A, \u0447\u0438\u0440\u0430\u0432\u0430\u043A\u0430 \u0438 \u0442.\u0434.- \u0442\u0430\u043A\u043E\u0432 \u0437\u0432\u0443\u043A, \u0434\u0435\u0441\u044F\u0442\u0435\u0440\u0438\u0447\u043D\u043E \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u043C\u044B\u0439. \u0412\u0438\u0433\u0440\u0430\u0445\u0430 \u2013 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \xAB\u044F\xBB (\u0430\u043D\u0443), \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u0432 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0445\u043E\u0442\u044F \u043E\u043D\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E .</p></div><div class="stanza"><a href="#s12.13" id="s12.13" class="num">12.13</a><p>\u0423 \u043C\u0438\u0440\u043E\u0432 \u043D\u0435\u0442 \u0447\u0438\u0441\u043B\u0430, \u0447\u0438\u0441\u043B\u043E \u0432\u0430\u0440\u043D \u2013 \u043F\u043E\u043B\u0441\u043E\u0442\u043D\u0438. \u0427\u0442\u043E-\u0442\u043E \u043E\u0434\u043D\u043E \u0434\u043B\u044F \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u0431\u0440\u0430\u0442\u044C, \u0434\u043B\u044F \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \u0441 \u044D\u0442\u0438\u043C .</p></div><div class="stanza"><a href="#s12.14" id="s12.14" class="num">12.14</a><p>\u0414\u0440\u0443\u0433\u043E\u0435 \u043A \u043F\u043B\u043E\u0434\u0430\u043C \u043D\u0435 \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0432\u0435\u0434\u0443\u0449\u0438\u043C \u043A \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438. \u0423 \u043D\u0435\u0433\u043E \u043E\u0434\u0438\u043D \u043F\u043B\u043E\u0434 \u2013 \u0432 \u043D\u0435\u043C \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u0443\u043C\u0430 .</p></div><div class="stanza"><a href="#s12.15" id="s12.15" class="num">12.15</a><p>\u0414\u0443\u0448\u0430, \u043E\u0447\u0438\u0449\u0435\u043D\u043D\u0430\u044F \u0445\u043E\u043C\u043E\u0439 \u0438 \u0434\u0438\u043A\u0448\u0435\u0439 \u043E\u0431\u0443\u0447\u0435\u043D\u043D\u0430\u044F \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F (\u0441\u0430\u043C\u0430\u0432\u0435\u0448\u0430), \u0436\u0435\u043B\u0430\u044E\u0449\u0430\u044F \u043E\u0431\u0440\u0435\u0441\u0442\u0438 \u0439\u043E\u0433\u0443 \u0434\u043E\u043B\u0436\u043D\u0430 \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C (\u044D\u0442\u0443 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443) .</p></div><div class="stanza"><a href="#s12.16" id="s12.16" class="num">12.16</a><p>\u041F\u043E\u043C\u0435\u0441\u0442\u0438\u0432 \u043D\u0430 \u043E\u0431\u0435 \u0440\u0443\u043A\u0438 \u0432\u044B\u0441\u0448\u0443\u044E \u0431\u0438\u0434\u0436\u0443, \u043F\u0443\u0441\u0442\u044C \u043C\u0443\u0434\u0440\u044B\u0439, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0430\u0445\u0430\u043C\u0443\u0434\u0440\u044B, \u0432 \u043E\u0431\u0440\u0430\u0442\u043D\u043E\u043C \u043F\u043E\u0440\u044F\u0434\u043A\u0435 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 \u0428\u0430\u043A\u0442\u0438;</p></div><div class="stanza"><a href="#s12.17" id="s12.17" class="num">12.17</a><p>\u0421\u0438\u044F\u044E\u0449\u0443\u044E, \u043A\u0430\u043A \u043F\u043B\u0430\u043C\u044F \u043E\u0433\u043D\u044F, \u043E\u0442 \u043A\u043E\u043D\u0447\u0438\u043A\u043E\u0432 \u0441\u0442\u043E\u043F \u0434\u043E \u043C\u0430\u043A\u0443\u0448\u043A\u0438. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u043D\u0430\u043C\u0430\u0441\u043A\u0430\u0440. \u0422\u0430\u043A \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442\u0441\u044F \u0432 \u0441\u0435\u0440\u0434\u0446\u0435 \u043E\u0433\u043E\u043D\u044C .</p></div><div class="stanza"><a href="#s12.18" id="s12.18" class="num">12.18</a><p>\u0412 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0432\u044B\u0441\u0448\u0443\u044E \u0431\u0438\u0434\u0436\u0443, \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u044F\u0440\u043A\u0443\u044E. \u0415\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0442\u0440\u0438 \u043C\u0430\u0442\u0440\u044B, \u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0443\u044E \u0438\u0437 \u0442\u0440\u0435\u0445 \u041A\u0410 \u0438 \u041A\u0425\u0410 .</p></div><div class="stanza"><a href="#s12.19" id="s12.19" class="num">12.19</a><p>\u0417\u0430\u0442\u0435\u043C, \u043F\u043E\u0441\u043B\u0435 \u0441\u0442\u0430 \u0442\u0430\u043B\u0430, \u0439\u043E\u0433\u0438\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435 (\u0432 \u043D\u0435\u0435) \u0437\u0430 \u0441\u0435\u043C\u044C \u0434\u043D\u0435\u0439, \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 \u043E\u043D \u2013\u0443\u0431\u0438\u0439\u0446\u0430 \u0431\u0440\u0430\u0445\u043C\u0430\u043D\u0430. (\u0422\u0430\u043A) \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u043E .</p></div><div class="stanza"><a href="#s12.20" id="s12.20" class="num">12.20</a><p>\u0421 \u0442\u0435\u043B\u043E\u043C, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C \u0442\u0430\u043A\u043E\u0439 \u0430\u0432\u0435\u0448\u0435\u0439, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u044D\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u043E \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E ..20\u0430.</p><p>\u041A\u0430\u043A \u0431\u044B\u043B\u043E (\u043E\u043F\u0438\u0441\u0430\u043D\u043E) \u0443\u0447\u0438\u0442\u0435\u043B\u0435\u043C, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u043E \u0430\u0432\u0435\u0448\u0438.</p></div><div class="stanza"><a href="#s12.22" id="s12.22" class="num">12.22</a><p>\u041F\u0441\u043E\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F \u0432\u0430\u0441\u0430\u043D, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0441\u0442\u0443\u043F\u0438\u0442\u044C \u043A \u043E\u0432\u043B\u0430\u0434\u0435\u043D\u0438\u044E \u0441\u0442\u0443\u043F\u0435\u043D\u044F\u043C\u0438 (\u0439\u043E\u0433\u0438).</p><p>\u041F\u043E\u043A\u043B\u043E\u043D\u0438\u0432\u0448\u0438\u0441\u044C \u0413\u0430\u043D\u0430\u043D\u0430\u0442\u0445\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0442\u0440\u0435\u0445 \u0433\u0443\u0440\u0443, \u0442\u043E\u0433\u0434\u0430 \u0435\u0433\u043E \u0442\u0435\u043B\u043E \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F (\u044D\u0442\u0438\u043C \u0441\u043E\u0442\u0441\u043E\u044F\u043D\u0438\u0435\u043C). \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C, \u0441 \u0443\u043C\u043E\u043C \u043D\u0435 \u043E\u0442\u043A\u043B\u043E\u043D\u044F\u044E\u0449\u0438\u043C\u0441\u044F \u043D\u0438 \u043D\u0430 \u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u0432 \u0441\u0432\u043E\u0435\u043C \u0442\u0435\u043B\u0435, \u0441\u0438\u044F\u044E\u0449\u0438\u0439 \u043A\u0430\u043A \u0437\u043E\u043B\u043E\u0442\u043E \u0447\u0435\u0442\u044B\u0440\u0435\u0445\u0443\u0433\u043E\u043B\u044C\u043D\u0438\u043A, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439 \u0432\u0430\u0434\u0436\u0440\u0430\u043C\u0438 .</p></div><div class="stanza"><a href="#s12.23" id="s12.23" class="num">12.23</a><p>\u0417\u0430\u0442\u0435\u043C \u043E\u0431\u0440\u0435\u0442\u0435\u0442\u0441\u044F \u0442\u044F\u0436\u0435\u0441\u0442\u044C (\u0433\u0430\u0440\u0438\u043C\u0430) \u0437\u0430 \u0434\u0432\u0430\u0434\u0446\u0430\u0442\u044C \u0441\u0435\u043C\u044C \u0434\u043D\u0435\u0439. \u0417\u0430 \u0441\u0435\u043C\u044C \u0434\u043D\u0435\u0439 \u043E\u043D \u043F\u043E\u0431\u0435\u0434\u0438\u0442 \u0435\u0433\u043E (\u0442\u0435\u043B\u0430) \u0438\u043D\u0435\u0440\u0442\u043D\u043E\u0441\u0442\u044C .</p></div><div class="stanza"><a href="#s12.24" id="s12.24" class="num">12.24</a><p>\u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u043F\u043E\u0431\u0435\u0434\u0438\u0432\u0448\u0438\u043C \u0431\u043E\u043B\u0435\u0437\u043D\u0438 \u0441 \u0442\u0435\u043A\u0443\u0447\u0438\u043C \u0442\u0435\u043B\u043E\u043C. \u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 (\u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442) \u0432\u0430\u0434\u0436\u0440\u043D\u043E\u0435 \u0442\u0435\u043B\u043E, \u0437\u0430 \u0434\u0435\u0432\u044F\u0442\u044C \u043F\u0440\u0435\u0432\u0437\u043E\u0439\u0434\u0435\u0442 \u043D\u0430\u0433\u043E\u0432 .</p></div><div class="stanza"><a href="#s12.25" id="s12.25" class="num">12.25</a><p>\u041F\u043E\u0432\u0435\u0434\u0430\u043D\u0430 \u0422\u0435\u0431\u0435 \u0447\u0438\u0441\u0442\u0430\u044F \u043F\u0440\u0438\u0442\u0445\u0438\u0432\u0438 \u0434\u0445\u0430\u0440\u0430\u043D\u0430. \u0422\u0435\u043F\u0435\u0440\u044C \u043A\u0430\u043A \u043F\u0440\u0435\u0436\u0434\u0435, \u043E \u0414\u0435\u0432\u0438, \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u0442\u0435\u0431\u0435 \u043E \u0435\u0435 \u043F\u044F\u0442\u0435\u0440\u0438\u0447\u043D\u043E\u043C \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0438 .</p></div><div class="stanza"><a href="#s12.26" id="s12.26" class="num">12.26</a><p>\u0421\u043B\u0435\u0432\u0430 \u0438 \u0441\u043F\u0440\u0430\u0432\u0430 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0442\u0435\u043B\u043E, \u0441\u0438\u044F\u044E\u0449\u0435\u0435 \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0440\u0430\u0441\u043F\u043B\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u043C\u0443 \u0437\u043E\u043B\u043E\u0442\u0443, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u0432 \u0447\u0435\u0442\u044B\u0440\u0435\u0445\u0443\u0433\u043E\u043B\u044C\u043D\u043E\u0439 \u043C\u0430\u043D\u0434\u0430\u043B\u0435, \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u043E\u0439 \u0432\u0430\u0434\u0436\u0440\u0430\u043C\u0438 .</p></div><div class="stanza"><a href="#s12.27" id="s12.27" class="num">12.27</a><p>\u0417\u0430 \u0441\u0435\u043C\u044C \u0434\u043D\u0435\u0439 \u043E\u043D\u043E \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0442\u044F\u0436\u0435\u0441\u0442\u044C. \u0417\u0430 \u043C\u0435\u0441\u044F\u0446 \u043E\u043D\u043E \u043E\u0441\u0432\u043E\u0431\u043E\u0434\u0438\u0442\u0441\u044F \u043E\u0442 \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439. \u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0439\u043E\u0433\u0438\u043D, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u0432\u043D\u0443\u0442\u0440\u0438 \u0437\u0435\u043C\u043B\u0438, \u0432\u043E\u0438\u0441\u0442\u0438\u043D\u0443, \u0431\u0443\u0434\u0435\u0442 \u0437\u043D\u0430\u0442\u044C \u0432\u0441\u0435 .</p></div><div class="stanza"><a href="#s12.28" id="s12.28" class="num">12.28</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u043F\u043E\u043B\u0443\u0447\u0438\u0442 \u0432\u0441\u0435 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u043D\u0430 \u0437\u0435\u043C\u043B\u0435, \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u043D\u043E\u0439 \u0441\u0435\u043C\u044C\u044E \u043E\u043A\u0435\u0430\u043D\u0430\u043C\u0438. \u0412\u0442\u043E\u0440\u043E\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435 \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u043E, \u0442\u0435\u043F\u0435\u0440\u044C \u0443\u0441\u043B\u044B\u0448\u044C \u043E \u0442\u0440\u0435\u0442\u044C\u0435\u043C .</p></div><div class="stanza"><a href="#s12.29" id="s12.29" class="num">12.29</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0442\u0435\u043B\u043E, \u043A\u0430\u043A \u0435\u0441\u0442\u044C, \u043D\u043E \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0435 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438. (\u0422\u043E\u0433\u0434\u0430 \u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u043B\u043E\u0434 \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 \u0440\u0430\u043D\u0435\u0435, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043F\u0430\u0442\u0430\u043B\u043E\u0439 .</p></div><div class="stanza"><a href="#s12.30" id="s12.30" class="num">12.30</a><p>\u041F\u0440\u0438 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u043C (\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0438), \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C (\u0442\u0435\u043B\u043E) \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u0432 \u0441\u0435\u0440\u0434\u0446\u0435 \u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C \u0432 \u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0430\u043D\u0433\u0443\u043B, \u0441 \u043F\u0435\u0440\u0432\u043E\u0439 \u0432\u0430\u0440\u043D\u043E\u0439 \u0432 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435, \u0441\u043B\u0435\u0432\u0430 \u0438 \u0441\u043F\u0440\u0430\u0432\u0430 \u043D\u0435\u0443\u0441\u044B\u043F\u043D\u043E .</p></div><div class="stanza"><a href="#s12.31" id="s12.31" class="num">12.31</a><p>\u041E\u0431\u0440\u0435\u0442\u044F \u0432\u0441\u0435, \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0435 \u0440\u0430\u043D\u0435\u0435, \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u0432\u043B\u0430\u0434\u044B\u043A\u043E\u0439 \u043F\u0430\u0442\u0430\u043B\u044B. \u041E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u044D\u0442\u043E\u0439 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u0438 \u0432 \u043D\u0435\u0434\u0435\u044F\u043D\u0438\u0438. \u0412 \u043F\u044F\u0442\u043E\u043C (\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0438);</p></div><div class="stanza"><a href="#s12.32" id="s12.32" class="num">12.32</a><p>(\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442\u0441\u044F \u0442\u0435\u043B\u043E) \u0436\u0435\u043B\u0442\u043E\u0435 \u0441\u0438\u044F\u044E\u0449\u0435\u0435 \u043A\u0430\u043A \u0441\u043E\u043B\u043D\u0446\u0435. \u041F\u0440\u0438 \u0448\u0435\u0441\u0442\u043E\u043C- \u0447\u0435\u0440\u043D\u043E\u0435 \u0438 \u043C\u0430\u0441\u0441\u0438\u0432\u043D\u043E\u0435. \u041F\u0440\u0438 \u0441\u0435\u0434\u044C\u043C\u043E\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0442\u0449\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0435\u0433\u043E \u043F\u043B\u0435\u0449\u0443\u0449\u0438\u043C\u0441\u044F</p></div><div class="stanza"><a href="#s12.33" id="s12.33" class="num">12.33</a><p>\u0417\u0430\u0442\u0435\u043C \u043E\u043D \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E \u0431\u0443\u0434\u0435\u0442 \u0437\u043D\u0430\u0442\u044C \u0442\u0440\u0438 (\u043C\u0438\u0440\u0430): \u0431\u0445\u0443\u0440, \u0431\u0445\u0443\u0432\u0430\u0440 \u0438 \u0441\u0432\u0430\u0440, \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 (\u043C\u0438\u0440\u044B), \u0437\u0430 \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0435 \u043F\u0440\u0435\u0436\u0434\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u043B\u0435\u0442 .</p></div><div class="stanza"><a href="#s12.34" id="s12.34" class="num">12.34</a><p>(\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C) \u0421\u0430\u043A\u0430\u043B\u0443 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0443\u044E \u0432\u043D\u0443\u0442\u0440\u0438 \u0441\u0435\u0440\u0434\u0446\u0430 \u0438 \u0421\u0435\u0431\u044F (\u0410\u0442\u043C\u0430\u043D) \u0446\u0432\u0435\u0442\u0430 \u0437\u043E\u043B\u043E\u0442\u0430, \u0441\u0430\u043C\u043E\u0441\u0438\u044F\u044E\u0449\u0435\u0433\u043E, \u0438\u0437\u043B\u0443\u0447\u0430\u044E\u0449\u0435\u0433\u043E \u0432\u0435\u0441\u044C \u0441\u0432\u0435\u0442 \u0438\u0437\u043D\u0443\u0442\u0440\u0438 \u0442\u0435\u043B\u0430 .</p></div><div class="stanza"><a href="#s12.35" id="s12.35" class="num">12.35</a><p>\u0420\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u043D\u0430 \u043F\u0440\u0430\u0432\u043E\u0435 \u0438 \u043B\u0435\u0432\u043E\u0435 \u0438 \u0441\u0435\u043C\u044C \u043C\u0438\u0440\u043E\u0432, \u043A\u0430\u043A \u0438 \u043F\u0440\u0435\u0436\u0434\u0435, \u043C\u0443\u0434\u0440\u044B\u0439 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E \u043F\u043E\u0437\u043D\u0430\u0435\u0442 \u0432\u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0438 \u0432 \u044D\u0442\u043E\u043C, \u0434\u0435\u0432\u044F\u0442\u043E\u043C \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0438 .</p></div><div class="stanza"><a href="#s12.36" id="s12.36" class="num">12.36</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u043E\u043B\u043D\u0435\u0447\u043D\u044B\u0439 \u0434\u0438\u0441\u043A, \u0436\u0435\u043B\u0442\u044B\u0439 \u043A\u0430\u043A \u043F\u0440\u0435\u0436\u0434\u0435. \u0422\u0430\u043A \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043C\u0438\u0440 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430, \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u043C \u0432\u044B\u0448\u0435 \u043F\u0443\u0442\u0435\u043C .</p></div><div class="stanza"><a href="#s12.37" id="s12.37" class="num">12.37</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0435\u0433\u043E \u0441\u0432\u0435\u0442, \u0441\u0438\u044F\u044E\u0449\u0438\u0439, \u0436\u0435\u043B\u0442\u044B\u0439 \u043A\u0430\u043A \u0438 \u043F\u0440\u0435\u0436\u0434\u0435. (\u0422\u043E\u0433\u0434\u0430), \u0441\u0442\u0430\u0432 \u0440\u0430\u0432\u043D\u044B\u043C \u041C\u043D\u0435, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u041C\u043E\u0435\u0433\u043E \u043C\u0438\u0440\u0430 .</p></div><div class="stanza"><a href="#s12.38" id="s12.38" class="num">12.38</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0432\u0435\u0442, \u0436\u0435\u043B\u0442\u044B\u0439, \u0432\u0441\u0435 \u043E\u0441\u0432\u0435\u0449\u0430\u044E\u0449\u0438\u0439 \u0432\u043D\u0443\u0442\u0440\u0438 \u0438 \u0441\u043D\u0430\u0440\u0443\u0436\u0438. (\u0422\u043E\u0433\u0434\u0430 \u043E\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u043E \u043D\u0430 \u0428\u0430\u0442\u0430\u0440\u0443\u0434\u0440\u0430\u043C\u0438 .</p></div><div class="stanza"><a href="#s12.39" id="s12.39" class="num">12.39</a><p>\u0422\u0430\u043A \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u0435\u0442\u0441\u044F \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u0438\u0440\u0438\u0447\u043D\u043E\u0435 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 \u043F\u0440\u0438\u0442\u0445\u0438\u0432\u0438 \u0442\u0430\u0442\u0442\u0432\u044B \u0439\u043E\u0433\u0438\u043D\u0430\u043C\u0438, \u0440\u0430\u0434\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0432 \u0439\u043E\u0433\u0435 \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u043C\u0438 \u0435\u0435 \u043F\u043B\u043E\u0434\u043E\u0432 .</p></div><div class="stanza"><a href="#s12.40" id="s12.40" class="num">12.40</a><p>\u0421\u043E\u0437\u0440\u0435\u0432\u0430\u043D\u0438\u0435 \u0433\u043E\u0442\u043E\u0432\u043D\u043E\u0441\u0442\u0438 (\u043A \u043D\u0435\u0439) \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u0432\u0430\u0441\u0430\u043D. \u0421 \u043D\u0435\u0439 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u0442\u0430\u0440\u0442\u0435\u043B\u044C\u043D\u043E \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0434\u0438\u043A\u0448\u0438 .</p></div><div class="stanza"><a href="#s12.41" id="s12.41" class="num">12.41</a><p>\u041A\u0442\u043E \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D \u0441 \u044D\u0442\u043E\u0439 \u0442\u0430\u0442\u0442\u0432\u043E\u0439, \u0442\u043E\u0442 \u043D\u0435 \u0432\u043E\u0437\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0438\u0437 \u043D\u0435\u0435. \u041E\u0431\u0440\u0435\u0442\u044F \u0432\u0441\u0435 \u0435\u0435 \u043F\u043B\u043E\u0434\u044B, \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u044B\u0439 \u0441 \u0428\u0438\u0432\u043E\u0439 \u043D\u0435 \u0440\u0430\u0437\u044A\u0435\u0434\u0438\u043D\u0438\u0442\u0441\u044F .</p></div><div class="stanza"><a href="#s12.42" id="s12.42" class="num">12.42</a><p>\u0414\u0430\u0436\u0435 \u043D\u0435 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u044B\u0439, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u044E \u0441\u0432\u044B\u0448\u0435 \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u043E \u043D\u0430\u0434 \u043C\u0438\u0440\u0430\u043C\u0438. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u044E \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0428\u0438\u0432\u044B, \u0441\u043E\u0436\u0433\u044F \u043E\u043A\u043E\u0432\u044B \u0441\u0430\u043C\u0441\u0430\u0440\u044B .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u0430\u044F \u0433\u043B\u0430\u0432\u0430</p>',42),n=[c];function l(v,t,e,r,m,u){return i(),a("div",null,n)}var z=s(p,[["render",l]]);export{h as __pageData,z as default};
